diffs.BaseSubScene.js_addResource_hook:
Inside the addResource onInteract callback, AFTER `audioMgr?.playSfx('item_pickup');`, added:

  // Optional scene-specific post-collect hook. Safe — wraps in try/catch so
  // scene-specific logic can't break generic resource collection.
  if (typeof config.onAfterCollect === 'function') {
    try { config.onAfterCollect(updated, this); }
    catch (e) {
      // eslint-disable-next-line no-console
      console.warn(`[addResource] onAfterCollect failed for ${config.itemId}`, e);
    }
  }

Purely additive — existing callers without `onAfterCollect` are unaffected because `typeof undefined === 'function'` is false.

diffs.CopperMineScene.js_helper_extraction:
Replaced the 22-line inline band-aid block in createWorld() (lines 36-58) with a single call `this._mintCopperOreSampleIfNeeded();` plus an updated banner comment. The extracted method `_mintCopperOreSampleIfNeeded()` was added just above `_handleMinerInteract()` with the exact same semantics as the original block:

  _mintCopperOreSampleIfNeeded() {
    const st = this.registry.get('gameState');
    const aq = st?.activeQuest;
    if (aq?.id !== 'bridge_collapse') return;
    if ((st.inventory || []).includes('copper_ore_sample')) return;
    const step = QUESTS.bridge_collapse?.steps?.[aq.stepIndex];
    if (step?.id !== 'collect_copper') return;
    const hasMineCopper = (st.inventory || []).some(
      (id) => id === 'surface_copper' || id === 'deep_copper'
    );
    if (!hasMineCopper) return;
    const updated = { ...st, inventory: [...st.inventory, 'copper_ore_sample'] };
    this.registry.set('gameState', updated);
    saveGame(updated);
    this.registry.set('dialogEvent', {
      speaker: 'Zuzu',
      text:
        "Wait — this copper from the mine works as a sample for Mr. Chen's bridge test!\n\n" +
        '🟤 Got: Copper Ore Sample',
      choices: null,
      step: null,
    });
  }
